module mux_4to1(
    input [3:0] input_data,
    input [1:0] select,
    output reg out
);

always @*
begin
    case (select)
        2'b00: out = input_data[0];
        2'b01: out = input_data[1];
        2'b10: out = input_data[2];
        2'b11: out = input_data[3];
        default: out = 0;
    endcase
end

endmodule
